const nodeId = msg.topic
    || (msg.addressSpaceItems && msg.addressSpaceItems[0] && msg.addressSpaceItems[0].value)
    || (msg.payload && msg.payload.nodeId && (msg.payload.nodeId.value || msg.payload.nodeId));

if (!nodeId || !tagMap[nodeId]) return null;

let rawVal = msg.payload;
if (rawVal !== null && rawVal !== undefined && typeof rawVal === 'object') {
    rawVal = (rawVal.value && rawVal.value.value !== undefined) ? rawVal.value.value
           : rawVal.value !== undefined ? rawVal.value
           : rawVal;
}

const num = parseFloat(rawVal);
if (!isNaN(num)) {
    flow.set(tagMap[nodeId], num);
}

return null;

const now = new Date();
now.setSeconds(0, 0);
const ts = now.toISOString().replace('T', ' ').substring(0, 19);

function g(k) {
    const v = flow.get(k);
    return (v === undefined || v === null || isNaN(parseFloat(v))) ? null : parseFloat(v);
}
function sql(k) { const v = g(k); return v === null ? 'NULL' : v; }

